func (this *Exchange) NetworkCodeToId(networkCode any, optionalArgs ...any) any {
	/**
	 * @ignore
	 * @method
	 * @name exchange#networkCodeToId
	 * @description tries to convert the provided networkCode (which is expected to be an unified network code) to a network id. In order to achieve this, derived class needs to have 'options->networks' defined.
	 * @param {string} networkCode unified network code
	 * @param {string} currencyCode unified currency code, but this argument is not required by default, unless there is an exchange (like huobi) that needs an override of the method to be able to pass currencyCode argument additionally
	 * @returns {string|undefined} exchange-specific network id
	 */
	currencyCode := GetArg(optionalArgs, 0, nil)
	_ = currencyCode
	if IsTrue(IsEqual(networkCode, nil)) {
		return nil
	}
	var networkIdsByCodes any = this.SafeValue(this.Options, "networks", map[string]any{})
	var networkId any = this.SafeString(networkIdsByCodes, networkCode)
	// for example, if 'ETH' is passed for networkCode, but 'ETH' key not defined in `options->networks` object
	if IsTrue(IsEqual(networkId, nil)) {
		if IsTrue(IsEqual(currencyCode, nil)) {
			var currencies any = ObjectValues(this.Currencies)
			for i := 0; IsLessThan(i, GetArrayLength(currencies)); i++ {
				var currency any = GetValue(currencies, i)
				var networks any = this.SafeDict(currency, "networks")
				var network any = this.SafeDict(networks, networkCode)
				networkId = this.SafeString(network, "id")
				if IsTrue(!IsEqual(networkId, nil)) {
					break
				}
			}
		} else {
			// if currencyCode was provided, then we try to find if that currencyCode has a replacement (i.e. ERC20 for ETH) or is in the currency
			var defaultNetworkCodeReplacements any = this.SafeValue(this.Options, "defaultNetworkCodeReplacements", map[string]any{})
			if IsTrue(InOp(defaultNetworkCodeReplacements, currencyCode)) {
				// if there is a replacement for the passed networkCode, then we use it to find network-id in `options->networks` object
				var replacementObject any = GetValue(defaultNetworkCodeReplacements, currencyCode) // i.e. { 'ERC20': 'ETH' }
				var keys any = ObjectKeys(replacementObject)
				for i := 0; IsLessThan(i, GetArrayLength(keys)); i++ {
					var key any = GetValue(keys, i)
					var value any = GetValue(replacementObject, key)
					// if value matches to provided unified networkCode, then we use it's key to find network-id in `options->networks` object
					if IsTrue(IsEqual(value, networkCode)) {
						networkId = this.SafeString(networkIdsByCodes, key)
						break
					}
				}
			} else {
				// serach for network inside currency
				var currency any = this.SafeDict(this.Currencies, currencyCode)
				var networks any = this.SafeDict(currency, "networks")
				var network any = this.SafeDict(networks, networkCode)
				networkId = this.SafeString(network, "id")
			}
		}
		// if it wasn't found, we just set the provided value to network-id
		if IsTrue(IsEqual(networkId, nil)) {
			networkId = networkCode
		}
	}
	return networkId
}
func (this *Exchange) NetworkIdToCode(optionalArgs ...any) any {
	/**
	 * @ignore
	 * @method
	 * @name exchange#networkIdToCode
	 * @description tries to convert the provided exchange-specific networkId to an unified network Code. In order to achieve this, derived class needs to have "options['networksById']" defined.
	 * @param {string} networkId exchange specific network id/title, like: TRON, Trc-20, usdt-erc20, etc
	 * @param {string|undefined} currencyCode unified currency code, but this argument is not required by default, unless there is an exchange (like huobi) that needs an override of the method to be able to pass currencyCode argument additionally
	 * @returns {string|undefined} unified network code
	 */
	networkId := GetArg(optionalArgs, 0, nil)
	_ = networkId
	currencyCode := GetArg(optionalArgs, 1, nil)
	_ = currencyCode
	if IsTrue(IsEqual(networkId, nil)) {
		return nil
	}
	var networkCodesByIds any = this.SafeDict(this.Options, "networksById", map[string]any{})
	var networkCode any = this.SafeString(networkCodesByIds, networkId, networkId)
	// replace mainnet network-codes (i.e. ERC20->ETH)
	if IsTrue(!IsEqual(currencyCode, nil)) {
		var defaultNetworkCodeReplacements any = this.SafeDict(this.Options, "defaultNetworkCodeReplacements", map[string]any{})
		if IsTrue(InOp(defaultNetworkCodeReplacements, currencyCode)) {
			var replacementObject any = this.SafeDict(defaultNetworkCodeReplacements, currencyCode, map[string]any{})
			networkCode = this.SafeString(replacementObject, networkCode, networkCode)
		}
	}
	return networkCode
}
func (this *Exchange) HandleNetworkCodeAndParams(params any) any {
	var networkCodeInParams any = this.SafeString2(params, "networkCode", "network")
	if IsTrue(!IsEqual(networkCodeInParams, nil)) {
		params = this.Omit(params, []any{"networkCode", "network"})
	}
	// if it was not defined by user, we should not set it from 'defaultNetworks', because handleNetworkCodeAndParams is for only request-side and thus we do not fill it with anything. We can only use 'defaultNetworks' after parsing response-side
	return []any{networkCodeInParams, params}
}
func (this *Exchange) DefaultNetworkCode(currencyCode any) any {
	var defaultNetworkCode any = nil
	var defaultNetworks any = this.SafeDict(this.Options, "defaultNetworks", map[string]any{})
	if IsTrue(InOp(defaultNetworks, currencyCode)) {
		// if currency had set its network in "defaultNetworks", use it
		defaultNetworkCode = GetValue(defaultNetworks, currencyCode)
	} else {
		// otherwise, try to use the global-scope 'defaultNetwork' value (even if that network is not supported by currency, it doesn't make any problem, this will be just used "at first" if currency supports this network at all)
		var defaultNetwork any = this.SafeString(this.Options, "defaultNetwork")
		if IsTrue(!IsEqual(defaultNetwork, nil)) {
			defaultNetworkCode = defaultNetwork
		}
	}
	return defaultNetworkCode
}
func (this *Exchange) SelectNetworkCodeFromUnifiedNetworks(currencyCode any, networkCode any, indexedNetworkEntries any) any {
	return this.SelectNetworkKeyFromNetworks(currencyCode, networkCode, indexedNetworkEntries, true)
}
func (this *Exchange) SelectNetworkIdFromRawNetworks(currencyCode any, networkCode any, indexedNetworkEntries any) any {
	return this.SelectNetworkKeyFromNetworks(currencyCode, networkCode, indexedNetworkEntries, false)
}
func (this *Exchange) SelectNetworkKeyFromNetworks(currencyCode any, networkCode any, indexedNetworkEntries any, optionalArgs ...any) any {
	// this method is used against raw & unparse network entries, which are just indexed by network id
	isIndexedByUnifiedNetworkCode := GetArg(optionalArgs, 0, false)
	_ = isIndexedByUnifiedNetworkCode
	var chosenNetworkId any = nil
	var availableNetworkIds any = ObjectKeys(indexedNetworkEntries)
	var responseNetworksLength any = GetArrayLength(availableNetworkIds)
	if IsTrue(!IsEqual(networkCode, nil)) {
		if IsTrue(IsEqual(responseNetworksLength, 0)) {
			panic(NotSupported(Add(Add(Add(Add(this.Id, " - "), networkCode), " network did not return any result for "), currencyCode)))
		} else {
			// if networkCode was provided by user, we should check it after response, as the referenced exchange doesn't support network-code during request
			var networkIdOrCode any = Ternary(IsTrue(isIndexedByUnifiedNetworkCode), networkCode, this.NetworkCodeToId(networkCode, currencyCode))
			if IsTrue(InOp(indexedNetworkEntries, networkIdOrCode)) {
				chosenNetworkId = networkIdOrCode
			} else {
				panic(NotSupported(Add(Add(Add(Add(Add(Add(this.Id, " - "), networkIdOrCode), " network was not found for "), currencyCode), ", use one of "), Join(availableNetworkIds, ", "))))
			}
		}
	} else {
		if IsTrue(IsEqual(responseNetworksLength, 0)) {
			panic(NotSupported(Add(Add(this.Id, " - no networks were returned for "), currencyCode)))
		} else {
			// if networkCode was not provided by user, then we try to use the default network (if it was defined in "defaultNetworks"), otherwise, we just return the first network entry
			var defaultNetworkCode any = this.DefaultNetworkCode(currencyCode)
			var defaultNetworkId any = Ternary(IsTrue(isIndexedByUnifiedNetworkCode), defaultNetworkCode, this.NetworkCodeToId(defaultNetworkCode, currencyCode))
			if IsTrue(InOp(indexedNetworkEntries, defaultNetworkId)) {
				return defaultNetworkId
			}
			panic(NotSupported(Add(Add(this.Id, " - can not determine the default network, please pass param[\"network\"] one from : "), Join(availableNetworkIds, ", "))))
		}
	}
	return chosenNetworkId
}
