func (this *Exchange) IsLeveragedCurrency(currencyCode any, optionalArgs ...any) any {
	checkBaseCoin := GetArg(optionalArgs, 0, false)
	_ = checkBaseCoin
	existingCurrencies := GetArg(optionalArgs, 1, nil)
	_ = existingCurrencies
	var leverageSuffixes any = []any{"2L", "2S", "3L", "3S", "4L", "4S", "5L", "5S", "UP", "DOWN", "BULL", "BEAR"}
	for i := 0; IsLessThan(i, GetArrayLength(leverageSuffixes)); i++ {
		var leverageSuffix any = GetValue(leverageSuffixes, i)
		if IsTrue(EndsWith(currencyCode, leverageSuffix)) {
			if !IsTrue(checkBaseCoin) {
				return true
			} else {
				// check if base currency is inside dict
				var baseCurrencyCode any = Replace(currencyCode, leverageSuffix, "")
				if IsTrue(InOp(existingCurrencies, baseCurrencyCode)) {
					return true
				}
			}
		}
	}
	return false
}
func (this *Exchange) HandleWithdrawTagAndParams(tag any, params any) any {
	if IsTrue(this.IsDictionary(tag)) {
		params = this.Extend(tag, params)
		tag = nil
	}
	if IsTrue(IsEqual(tag, nil)) {
		tag = this.SafeString(params, "tag")
		if IsTrue(!IsEqual(tag, nil)) {
			params = this.Omit(params, "tag")
		}
	}
	return []any{tag, params}
}
